#include <bits/stdc++.h>
#define int long long
using namespace std;
struct Edge {
	int L , R , lzcf , lzjf , sum;
}; 
Edge tr[400005];
int a[400005];
int m;
int n , mod;
void build( int p , int L , int R ) {
	tr[p].L = L , tr[p].R = R , tr[p].sum = 0 , tr[p].lzcf = 1 , tr[p].lzjf = 0;
	if( L == R ) {
		return;
	}
	int mid = ( L + R ) / 2;
	build( p << 1 , L , mid );
	build( ( p << 1 ) + 1 , mid + 1 , R );
}
void uplz( int p , int lzcf , int lzjf ) {
	tr[p].sum = tr[p].sum * lzcf % mod;
	tr[p].sum = ( tr[p].sum + ( tr[p].R - tr[p].L + 1 ) * lzjf ) % mod;
	tr[p].lzcf = tr[p].lzcf * lzcf % mod;
	tr[p].lzjf = ( tr[p].lzjf * lzcf + lzjf ) % mod;
}
void pushdown( int p ) {
	if( tr[p].lzcf != 1 || tr[p].lzjf != 0 ) {
		uplz( p << 1 , tr[p].lzcf , tr[p].lzjf );
		uplz( ( p << 1 ) + 1 , tr[p].lzcf , tr[p].lzjf );
		tr[p].lzcf = 1 , tr[p].lzjf = 0;
	}
}
void modify( int p , int l , int r , int lc , int lj ) {
	if( tr[p].L > r || tr[p].R < l ) {
		return;
	}
	if( tr[p].L >= l && tr[p].R <= r ) {
		uplz( p , lc , lj );
		return;
	}
	pushdown( p );
	modify( p << 1 , l , r , lc , lj );
	modify( ( p << 1 ) + 1 , l , r , lc , lj );
	tr[p].sum = ( tr[p << 1].sum + tr[( p << 1 ) + 1].sum ) % mod;
}
int query( int p , int a , int b ) {
	if( tr[p].L > b || tr[p].R < a ) {
		return 0;
	}
	if( tr[p].L >= a && tr[p].R <= b ) {
		return tr[p].sum;
	}
	int sum = 0;
	pushdown( p );
	sum += query( p << 1 , a , b );
	sum += query( ( p << 1 ) + 1 , a , b );
	return sum % mod;
}
signed main() {
	cin >> n >> m >> mod;
	build( 1 , 1 , n );
	for( int i = 1 ; i <= n ; i++ ) {
		int x;
		cin >> x;
		modify( 1 , i , i , 1 , x );
	}
	while( m-- ) {
		int op;
		int x , y , k;
		cin >> op;
		cin >> x >> y;
		if( op == 1 ) {
			cin >> k;
			modify( 1 , x , y , k , 0 );
		} else if( op == 2 ) {
			cin >> k;
			modify( 1 , x , y , 1 , k );
		} else if( op == 3 ) {
			cout << query( 1 , x , y ) << '\n';
		}
	}
	return 0;
}
